-- Records of articles
-- ----------------------------
INSERT INTO `articles` VALUES (2, 'Linux LVM逻辑卷管理详解', 'linux-lvm', '<h2 style=\"text-align: start;\">什么是LVM？</h2><p style=\"text-align: start;\">LVM是逻辑盘卷管理（Logical Volume Manager）的简称，它是Linux环境下对磁盘分区进行管理的一种机制，LVM是建立在硬盘和分区之上的一个逻辑层，来提高磁盘分区管理的灵活性。</p><h2 style=\"text-align: start;\">为什么要使用LVM？</h2><p style=\"text-align: start;\">在日常工作或者学习中，随着电脑的不断被使用，我们的磁盘空间可能会越来越小，这时候，我们不能直接更换大硬盘，因为硬盘有价，数据无价，这时候我们就可以使用LVM，LVM将存储虚拟化,使用逻辑卷,你不会受限于物理磁盘的大小,另外,和硬件相关的存储设置被其隐藏,你能不用停止应用或卸载文件系统来调整卷大小或数据迁移.这样能减少操作成本，LVM最大的特点就是可以对磁盘进行动态管理。因为逻辑卷的大小是可以动态调整的，而且不会丢失现有的数据。如果我们新增加了硬盘，其也不会改变现有上层的逻辑卷。作为一个动态磁盘管理机制，逻辑卷技术大大提高了磁盘管理的灵活性。</p><h2 style=\"text-align: start;\">LVM工作机制</h2><p style=\"text-align: start;\">LVM就是通过将底层的物理硬盘抽象的封装起来，然后以逻辑卷的方式呈现给上层应用。在传统的磁盘管理机制中，我们的上层应用是直接访问文件系统，从而对底层的物理硬盘进行读取，而在LVM中，其通过对底层的硬盘进行封装，当我们对底层的物理硬盘进行操作时，其不再是针对于分区进行操作，而是通过一个叫做逻辑卷的东西来对其进行底层的磁盘管理操作。</p><h2 style=\"text-align: start;\">逻辑卷管理概念</h2><h3 style=\"text-align: start;\">物理卷（PV, Physical Volume）</h3><p style=\"text-align: start;\">物理卷就是指磁盘,磁盘分区或从逻辑上和磁盘分区具有同样功能的设备(如RAID)，是LVM的基本存储逻辑块，但和基本的物理存储介质（如分区、磁盘等）比较，却包含有和LVM相关的管理参数。当前LVM允许你在每个物理卷上保存这个物理卷的0至2份元数据拷贝.默认为1,保存在设备的开始处.为2时,在设备结束处保存第二份备份.</p><h3 style=\"text-align: start;\">卷组（VG, Volume Group）</h3><p style=\"text-align: start;\">LVM卷组类似于非LVM系统中的物理硬盘，其由物理卷组成。能在卷组上创建一个或多个\"LVM分区\"（逻辑卷），LVM卷组由一个或多个物理卷组成。</p><h3 style=\"text-align: start;\">逻辑卷（LV, Logical Volume）</h3><p style=\"text-align: start;\">LVM的逻辑卷类似于非LVM系统中的硬盘分区，在逻辑卷之上能建立文件系统(比如/home或/usr等)。</p><h3 style=\"text-align: start;\">关系结构</h3><p>复制代码</p><pre><code >物理硬盘 → 物理卷(PV) → 卷组(VG) → 逻辑卷(LV) → 文件系统</code></pre><h2 style=\"text-align: start;\">LVM操作实战</h2><h3 style=\"text-align: start;\">1. 检查系统是否安装了LVM管理工具</h3><p>bash复制代码</p><pre><code class=\"language-bash\">rpm -qa|grep lvm</code></pre><p style=\"text-align: start;\">输出示例：</p><p style=\"text-align: start;\">复制代码</p><pre><code >lvm2-2.02.177-4.el7.x86_64\r\nllvm-private-5.0.0-3.el7.x86_64\r\nlvm2-libs-2.02.177-4.el7.x86_64</code></pre><h3 style=\"text-align: start;\">2. 安装LVM工具（如果未安装）</h3><p>bash复制代码</p><pre><code class=\"language-bash\">yum install lvm*</code></pre><h3 style=\"text-align: start;\">3. 创建物理卷(PV)</h3><p style=\"text-align: start;\">基本PV命令：</p><ul><li style=\"text-align: start;\"><span style=\"color: rgb(53, 148, 247); background-color: rgba(59, 170, 250, 0.1);\"><code>pvcreate</code></span>：将物理分区新建为pv</li><li style=\"text-align: start;\"><span style=\"color: rgb(53, 148, 247); background-color: rgba(59, 170, 250, 0.1);\"><code>pvs</code></span>/<span style=\"color: rgb(53, 148, 247); background-color: rgba(59, 170, 250, 0.1);\"><code>pvscan</code></span>：查看系统里有pv的磁盘</li><li style=\"text-align: start;\"><span style=\"color: rgb(53, 148, 247); background-color: rgba(59, 170, 250, 0.1);\"><code>pvdisplay</code></span>：显示系统上面的pv状态</li><li style=\"text-align: start;\"><span style=\"color: rgb(53, 148, 247); background-color: rgba(59, 170, 250, 0.1);\"><code>pvremove</code></span>：删除pv</li></ul><p style=\"text-align: start;\">使用两个磁盘：<span style=\"color: rgb(53, 148, 247); background-color: rgba(59, 170, 250, 0.1);\"><code>/dev/sdl</code></span> (20G) 和 <span style=\"color: rgb(53, 148, 247); background-color: rgba(59, 170, 250, 0.1);\"><code>/dev/sdh</code></span> (1G) 来完成LVM</p><p style=\"text-align: start;\">bash复制代码</p><pre><code class=\"language-bash\">pvcreate /dev/sdl /dev/sdh</code></pre><p style=\"text-align: start;\">输出：</p><p style=\"text-align: start;\">复制代码</p><pre><code >Physical volume \"/dev/sdl\" successfully created.\r\nPhysical volume \"/dev/sdh\" successfully created.</code></pre><p style=\"text-align: start;\">查看新建的PV：</p><p style=\"text-align: start;\">bash复制代码</p><pre><code class=\"language-bash\">pvs</code></pre><p style=\"text-align: start;\">输出：</p><p style=\"text-align: start;\">复制代码</p><pre><code >PV      VG  Fmt  Attr PSize  PFree\r\n/dev/sdh    lvm2 ---   1.00g  1.00g\r\n/dev/sdl    lvm2 ---  20.00g 20.00g</code></pre><h3 style=\"text-align: start;\">4. 创建卷组(VG)</h3><p style=\"text-align: start;\">有关VG的命令：</p><ul><li style=\"text-align: start;\"><span style=\"color: rgb(53, 148, 247); background-color: rgba(59, 170, 250, 0.1);\"><code>vgcreate [-s xM] vgName /dev/sd...</code></span>：新建vg，-s后面接pe的大小（可选）</li><li style=\"text-align: start;\"><span style=\"color: rgb(53, 148, 247); background-color: rgba(59, 170, 250, 0.1);\"><code>vgextend</code></span>：扩展vg，就是增加pv</li><li style=\"text-align: start;\"><span style=\"color: rgb(53, 148, 247); background-color: rgba(59, 170, 250, 0.1);\"><code>vgs</code></span>/<span style=\"color: rgb(53, 148, 247); background-color: rgba(59, 170, 250, 0.1);\"><code>vgscan</code></span>：查看系统里有vg的磁盘</li><li style=\"text-align: start;\"><span style=\"color: rgb(53, 148, 247); background-color: rgba(59, 170, 250, 0.1);\"><code>vgdisplay</code></span>：显示系统上面的vg状态</li><li style=\"text-align: start;\"><span style=\"color: rgb(53, 148, 247); background-color: rgba(59, 170, 250, 0.1);\"><code>vgremove</code></span>：删除vg</li><li style=\"text-align: start;\"><span style=\"color: rgb(53, 148, 247); background-color: rgba(59, 170, 250, 0.1);\"><code>vgreduce</code></span>：在vg里删除pv</li></ul><p style=\"text-align: start;\">创建vgqjc并查看：</p><p style=\"text-align: start;\">bash复制代码</p><pre><code class=\"language-bash\">vgcreate -s 16M vgqjc /dev/sdl\r\nvgs</code></pre><p style=\"text-align: start;\">输出：</p><p style=\"text-align: start;\">复制代码</p><pre><code >VG    #PV #LV #SN Attr VSize   VFree\r\nvgqjc   1   0   0 wz--n-  19.98g 19.98g</code></pre><h3 style=\"text-align: start;\">5. 创建逻辑卷(LV)</h3><p style=\"text-align: start;\">有关LV的命令：</p><ul><li style=\"text-align: start;\"><span style=\"color: rgb(53, 148, 247); background-color: rgba(59, 170, 250, 0.1);\"><code>lvcreate -l pe num /-L size -n lvname vgName</code></span>：新建lv，-l指定pe的个数，-L指定容量</li><li style=\"text-align: start;\"><span style=\"color: rgb(53, 148, 247); background-color: rgba(59, 170, 250, 0.1);\"><code>lvextend</code></span>：增加容量</li><li style=\"text-align: start;\"><span style=\"color: rgb(53, 148, 247); background-color: rgba(59, 170, 250, 0.1);\"><code>lvs</code></span>/<span style=\"color: rgb(53, 148, 247); background-color: rgba(59, 170, 250, 0.1);\"><code>lvscan</code></span>：查看系统里有lv的磁盘</li><li style=\"text-align: start;\"><span style=\"color: rgb(53, 148, 247); background-color: rgba(59, 170, 250, 0.1);\"><code>lvdisplay</code></span>：显示系统上面的lv状态</li><li style=\"text-align: start;\"><span style=\"color: rgb(53, 148, 247); background-color: rgba(59, 170, 250, 0.1);\"><code>lvremove</code></span>：删除lv</li><li style=\"text-align: start;\"><span style=\"color: rgb(53, 148, 247); background-color: rgba(59, 170, 250, 0.1);\"><code>lvreduce</code></span>：在lv里减少容量</li></ul><p style=\"text-align: start;\">创建lvqjc：</p><p style=\"text-align: start;\">bash复制代码</p><pre><code class=\"language-bash\">lvcreate -l 512 -n lvqjc vgqjc</code></pre><p style=\"text-align: start;\">输出：</p><p style=\"text-align: start;\">复制代码</p><pre><code >WARNING: ext4 signature detected on /dev/vgqjc/lvqjc at offset 1080. Wipe it? [y/n]: y\r\nWiping ext4 signature on /dev/vgqjc/lvqjc.\r\nLogical volume \"lvqjc\" created.</code></pre><p style=\"text-align: start;\">查看：</p><p style=\"text-align: start;\">bash复制代码</p><pre><code class=\"language-bash\">lvs</code></pre><p style=\"text-align: start;\">输出：</p><p style=\"text-align: start;\">复制代码</p><pre><code >LV    VG    Attr      LSize Pool Origin Data%  Meta%  Move Log Cpy%Sync Convert\r\nlvqjc vgqjc -wi-a----- 8.00g</code></pre><h3 style=\"text-align: start;\">6. 格式化逻辑卷</h3><p>bash复制代码</p><pre><code class=\"language-bash\">mkfs.ext4 /dev/vgqjc/lvqjc</code></pre><h3 style=\"text-align: start;\">7. 挂载使用</h3><p>bash复制代码</p><pre><code class=\"language-bash\">mount /dev/vgqjc/lvqjc /mnt\r\ndf -Th</code></pre><p style=\"text-align: start;\">输出显示逻辑卷已成功挂载到/mnt目录。</p><h2 style=\"text-align: start;\">LVM的在线扩展</h2><h3 style=\"text-align: start;\">情况一：VG空间足够</h3><p style=\"text-align: start;\">当需要扩展的PE数量，VG可以提供时：</p><p style=\"text-align: start;\">bash复制代码</p><pre><code class=\"language-bash\">lvextend -L +100M /dev/vgtest/lvtest\r\nresize2fs /dev/vgtest/lvtest  # 更新文件系统大小</code></pre><h3 style=\"text-align: start;\">情况二：VG空间不够</h3><p style=\"text-align: start;\">需要先扩展VG，即往VG中加PV：</p><p style=\"text-align: start;\">bash复制代码</p><pre><code class=\"language-bash\"># 新建PV\r\npvcreate /dev/sdg\r\n\r\n# 扩展VG\r\nvgextend vgtest /dev/sdg\r\n\r\n# 扩展LV\r\nlvextend -L 1G /dev/vgtest/lvtest\r\n\r\n# 更新文件系统\r\nresize2fs /dev/vgtest/lvtest</code></pre><h2 style=\"text-align: start;\">LVM的缩减操作</h2><p style=\"text-align: start;\"><strong>注意：缩减操作有风险，请确保数据已备份！</strong></p><ol><li style=\"text-align: start;\">卸载文件系统</li><li style=\"text-align: start;\">缩减文件系统</li><li style=\"text-align: start;\">缩减逻辑卷</li><li style=\"text-align: start;\"></li><li style=\"text-align: start;\"></li><li style=\"text-align: start;\"></li><li style=\"text-align: start;\">bash复制代码</li></ol><pre><code class=\"language-bash\"># 检查当前大小\r\nlvs\r\n\r\n# 缩减文件系统到5G\r\nresize2fs /dev/vgqjc/lvqjc 5G\r\n\r\n# 缩减逻辑卷到5G\r\nlvreduce -L 5G /dev/vgqjc/lvqjc\r\n\r\n# 重新挂载并验证\r\nmount /dev/vgqjc/lvqjc /mnt\r\ndf -Th\r\nls /mnt  # 检查文件是否丢失</code></pre><h2 style=\"text-align: start;\">删除LVM</h2><p style=\"text-align: start;\">如果要彻底移除LVM，需要按创建步骤的反向操作：</p><ol><li style=\"text-align: start;\">卸载文件系统</li><li style=\"text-align: start;\">删除LV</li><li style=\"text-align: start;\">删除VG</li><li style=\"text-align: start;\">删除PV</li><li style=\"text-align: start;\"></li><li style=\"text-align: start;\"></li><li style=\"text-align: start;\"></li><li style=\"text-align: start;\">bash复制代码</li></ol><pre><code class=\"language-bash\"># 卸载\r\numount /dev/mapper/vgqjc-lvqjc\r\n\r\n# 删除LV\r\nlvremove /dev/mapper/vgqjc-lvqjc\r\n\r\n# 删除VG\r\nvgremove /dev/mapper/vgqjc\r\n\r\n# 删除PV\r\npvremove /dev/sdl</code></pre><h2 style=\"text-align: start;\">常用命令总结</h2><h3 style=\"text-align: start;\">物理卷(PV)管理</h3><p>bash复制代码</p><pre><code class=\"language-bash\">pvcreate /dev/sdX      # 创建物理卷\r\npvs                    # 查看物理卷简要信息\r\npvdisplay              # 查看物理卷详细信息\r\npvremove /dev/sdX      # 删除物理卷</code></pre><h3 style=\"text-align: start;\">卷组(VG)管理</h3><p>bash复制代码</p><pre><code class=\"language-bash\">vgcreate vgname /dev/sdX    # 创建卷组\r\nvgs                         # 查看卷组简要信息\r\nvgdisplay                   # 查看卷组详细信息\r\nvgextend vgname /dev/sdX    # 扩展卷组\r\nvgreduce vgname /dev/sdX    # 从卷组中移除物理卷\r\nvgremove vgname             # 删除卷组</code></pre><h3 style=\"text-align: start;\">逻辑卷(LV)管理</h3><p>bash复制代码</p><pre><code class=\"language-bash\">lvcreate -L 大小 -n lvname vgname    # 创建逻辑卷\r\nlvs                                    # 查看逻辑卷简要信息\r\nlvdisplay                              # 查看逻辑卷详细信息\r\nlvextend -L +大小 /dev/vgname/lvname   # 扩展逻辑卷\r\nlvreduce -L 大小 /dev/vgname/lvname    # 缩减逻辑卷\r\nlvremove /dev/vgname/lvname            # 删除逻辑卷</code></pre><h3 style=\"text-align: start;\">文件系统操作</h3><p>bash复制代码</p><pre><code class=\"language-bash\">resize2fs /dev/vgname/lvname           # 调整ext文件系统大小\r\nmkfs.ext4 /dev/vgname/lvname           # 格式化逻辑卷\r\nmount /dev/vgname/lvname /mountpoint   # 挂载逻辑卷</code></pre><h2 style=\"text-align: start;\">注意事项</h2><ol><li style=\"text-align: start;\"><strong>备份重要数据</strong>：在进行LVM缩减操作前，务必备份重要数据</li><li style=\"text-align: start;\"><strong>在线扩展</strong>：LVM支持在线扩展，无需卸载文件系统</li><li style=\"text-align: start;\"><strong>缩减风险</strong>：缩减操作需要先卸载文件系统，操作不当可能导致数据丢失</li><li style=\"text-align: start;\"><strong>PE大小</strong>：创建卷组时可以通过<span style=\"color: rgb(53, 148, 247); background-color: rgba(59, 170, 250, 0.1);\"><code>-s</code></span>参数指定PE大小，影响后续扩展的粒度</li><li style=\"text-align: start;\"><strong>文件系统类型</strong>：不同文件系统使用不同的工具调整大小（ext系列用resize2fs，xfs用xfs_growfs）</li></ol><p><br></p>', 'LVM是逻辑盘卷管理（Logical Volume Manager）的简称，它是Linux环境下对磁盘分区进行管理的一种机制，LVM是建立在硬盘和分区之上的一个逻辑层，来提高磁盘分区管理的灵活性。', '/uploads/2026/03/1774445242660-l5hyf7vkuoo.png', 'published', 23, 0, '2026-03-25 13:27:42', '2026-03-25 17:21:48', 4, 1, '2025-03-10 14:24:00');
INSERT INTO `articles` VALUES (3, 'iptables 入门到跑路：15 条命令搞定 Linux 防火墙', 'iptables-15-linux', '<h2 style=\"text-align: start;\">为什么还学 iptables？</h2><p style=\"text-align: start;\">nftables、firewalld 喊了多年，但线上老系统依旧跑 iptables。<br>会翻规则、能救急，是运维的基本尊严。</p><hr/><p><br></p><h2 style=\"text-align: start;\">1. 看清现状：列出所有规则</h2><pre><code class=\"language-bash\">iptables -L -n --line-numbers</code></pre><h2 style=\"text-align: start;\"><span style=\"color: rgb(53, 148, 247); background-color: rgba(59, 170, 250, 0.1);\"><code>-n</code></span> 不把端口解析成服务名，速度翻倍。</h2><h2 style=\"text-align: start;\">2. 永久保存 &amp; 重载</h2><p style=\"text-align: start;\">CentOS 7 之前：</p><pre><code >service iptables save # 保存\r\nservice iptables restart # 重载</code></pre><p style=\"text-align: start;\">Debian/Ubuntu：</p><pre><code >apt install iptables-persistent\r\nnetfilter-persistent save\r\nnetfilter-persistent reload</code></pre><p><br></p><h2 style=\"text-align: start;\">3. 允许 SSH（22）——先保命</h2><pre><code >iptables -A INPUT -p tcp --dport 22 -j ACCEPT</code></pre><h2 style=\"text-align: start;\"><strong>远程操作前，先写一条允许当前会话的规则，再开默认 DROP，否则直接失联。</strong></h2><h2 style=\"text-align: start;\">4. 回环口全开</h2><pre><code >iptables -A INPUT -i lo -j ACCEPT</code></pre><h2 style=\"text-align: start;\">本地进程通信被误杀，会出各种玄学 bug。</h2><h2 style=\"text-align: start;\">5. 已建立连接放行</h2><pre><code >iptables -A INPUT -m state --state ESTABLISHED,RELATED -j ACCEPT</code></pre><h2 style=\"text-align: start;\">让服务器“出去”的流量能回来。</h2><h2 style=\"text-align: start;\">6. 禁 ping（可选）</h2><pre><code >iptables -A INPUT -p icmp --icmp-type 8 -j DROP</code></pre><h2 style=\"text-align: start;\">防扫描，但排障时别忘关掉。</h2><h2 style=\"text-align: start;\">7. 放行 Web 端口</h2><pre><code >iptables -A INPUT -p tcp -m multiport --dports 80,443 -j ACCEPT</code></pre><h2 style=\"text-align: start;\"><span style=\"color: rgb(53, 148, 247); background-color: rgba(59, 170, 250, 0.1);\"><code>multiport</code></span> 一次写多个端口，简洁。</h2><h2 style=\"text-align: start;\">8. 限制 SSH 来源</h2><pre><code >iptables -A INPUT -p tcp -s 10.0.0.0/8 --dport 22 -j ACCEPT</code></pre><h2 style=\"text-align: start;\">只允许内网登录，暴力破解直接归零。</h2><h2 style=\"text-align: start;\">9. 防 SYN Flood</h2><pre><code >iptables -A INPUT -p tcp --syn -m limit --limit 1/s --limit-burst 3 -j ACCEPT</code></pre><h2 style=\"text-align: start;\">超出速率的 SYN 包丢弃，轻量级抗 D。</h2><h2 style=\"text-align: start;\">10. 封杀单 IP</h2><pre><code >iptables -I INPUT -s 1.2.3.4 -j DROP</code></pre><h2 style=\"text-align: start;\"><span style=\"color: rgb(53, 148, 247); background-color: rgba(59, 170, 250, 0.1);\"><code>-I</code></span> 插到最前，立即生效。</h2><h2 style=\"text-align: start;\">11. 端口转发（DNAT）</h2><p style=\"text-align: start;\">把公网 8080 转到内网 192.168.1.10:80</p><pre><code >iptables -t nat -A PREROUTING -p tcp --dport 8080 -j DNAT --to 192.168.1.10:80\r\niptables -t nat -A POSTROUTING -d 192.168.1.10 -p tcp --dport 80 -j MASQUERADE</code></pre><h2 style=\"text-align: start;\">别忘了开 <span style=\"color: rgb(53, 148, 247); background-color: rgba(59, 170, 250, 0.1);\"><code>net.ipv4.ip_forward = 1</code></span></h2><h2 style=\"text-align: start;\">12. 屏蔽常见扫描</h2><pre><code >iptables -A INPUT -p tcp --tcp-flags ALL NONE -j DROP\r\niptables -A INPUT -p tcp --tcp-flags SYN,FIN SYN,FIN -j DROP</code></pre><h2 style=\"text-align: start;\">干掉 NULL 包与 SYN/FIN 畸形包。</h2><h2 style=\"text-align: start;\">13. 限速 SSH 暴力破解</h2><pre><code >iptables -A INPUT -p tcp --dport 22 -m state --state NEW -m recent --set\r\niptables -A INPUT -p tcp --dport 22 -m state --state NEW -m recent --update --seconds 60 --hitcount 4 -j DROP</code></pre><h2 style=\"text-align: start;\">60 秒内同一 IP 新建连接 ≥4 直接拉黑。</h2><h2 style=\"text-align: start;\">14. 日志记录（调试神器）</h2><pre><code >iptables -A INPUT -p tcp --dport 80 -j LOG --log-prefix \"HTTP: \" --log-level 4</code></pre><h2 style=\"text-align: start;\">配合 <span style=\"color: rgb(53, 148, 247); background-color: rgba(59, 170, 250, 0.1);\"><code>journalctl -k -f</code></span> 实时看命中情况。</h2><h2 style=\"text-align: start;\">15. 一键清空白链（慎点）</h2><pre><code >iptables -F\r\niptables -X\r\niptables -Z</code></pre><h2 style=\"text-align: start;\"><strong>本地终端执行，远程慎用！</strong></h2><h2 style=\"text-align: start;\">小结速查表</h2><table style=\"width: auto; text-align: start;\"><tbody><tr><th colspan=\"1\" rowspan=\"1\" width=\"auto\">场景</th><th colspan=\"1\" rowspan=\"1\" width=\"auto\">关键选项</th></tr><tr><td colspan=\"1\" rowspan=\"1\" width=\"auto\">放行端口</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\"><span style=\"color: rgb(53, 148, 247); background-color: rgba(59, 170, 250, 0.1);\"><code>-A INPUT -p tcp --dport N -j ACCEPT</code></span></td></tr><tr><td colspan=\"1\" rowspan=\"1\" width=\"auto\">封 IP</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\"><span style=\"color: rgb(53, 148, 247); background-color: rgba(59, 170, 250, 0.1);\"><code>-I INPUT -s IP -j DROP</code></span></td></tr><tr><td colspan=\"1\" rowspan=\"1\" width=\"auto\">已建立连接</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\"><span style=\"color: rgb(53, 148, 247); background-color: rgba(59, 170, 250, 0.1);\"><code>-m state --state ESTABLISHED,RELATED</code></span></td></tr><tr><td colspan=\"1\" rowspan=\"1\" width=\"auto\">端口转发</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\"><span style=\"color: rgb(53, 148, 247); background-color: rgba(59, 170, 250, 0.1);\"><code>-t nat -A PREROUTING … DNAT</code></span></td></tr><tr><td colspan=\"1\" rowspan=\"1\" width=\"auto\">限速</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\"><span style=\"color: rgb(53, 148, 247); background-color: rgba(59, 170, 250, 0.1);\"><code>-m limit --limit 1/s</code></span></td></tr><tr><td colspan=\"1\" rowspan=\"1\" width=\"auto\">永久保存</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\"><span style=\"color: rgb(53, 148, 247); background-color: rgba(59, 170, 250, 0.1);\"><code>service iptables save</code></span> / <span style=\"color: rgb(53, 148, 247); background-color: rgba(59, 170, 250, 0.1);\"><code>netfilter-persistent</code></span></td></tr></tbody></table><p><br></p>', '为什么还学 iptables？nftables、firewalld 喊了多年，但线上老系统依旧跑 iptables。会翻规则、能救急，是运维的基本尊严。', '/uploads/2026/03/1774448986332-gq6usyjo5e.png', 'published', 5, 0, '2026-03-25 14:34:46', '2026-03-25 15:55:16', 4, 1, '2025-08-14 04:32:00');
INSERT INTO `articles` VALUES (4, 'Linux系统故障修复', 'linux', '<p style=\"text-align: start;\">我发现Linux系统在启动过程中会出现一些故障，导致系统无法正常启动，我在这里写了几个应用单用户模式、GRUB命令操作、Linux救援模式的故障修复案例帮助大家了解此类问题的解决。</p><h1 style=\"text-align: start;\">（一）单用户模式</h1><p style=\"text-align: start;\">Linux系统提供了单用户模式(类似Windows安全模式)，可以在最小环境中进行系统维护。在单用户模式(运行级别1)中，Linux引导进入根shell，网络被禁用，只有少数进程运行。单用户模式可以用来修改文件系统损坏、还原配置文件、移动用户数据等。</p><p style=\"text-align: start;\">以下列举了几个单用户模式修复系统故障的典型案例：</p><h2 style=\"text-align: start;\">案例一：root密码忘记</h2><p style=\"text-align: start;\">在单用户模式中，Linux不需要root密码(Red Hat系统不需要root密码，但SuSe则需要，不同Linux系统稍有差别，本文以Fedora Core 6为例讲解)，这使更改root密码非常容易。了解当系统引导进入多用户模式失败时，如何进入单用户模式，非常重要。</p><h4 style=\"text-align: start;\">1、 在系统启动过程中，会出现开始界面，按任意键，进入GRUB菜单选项。</h4><p style=\"text-align: start;\">若希望以后无此提示，直接进入GRUB菜单选项，删除配置文件grub.conf中“hiddenmenu”项即可。</p><h4 style=\"text-align: start;\">2、 按“e”键编辑GRUB引导菜单选项，按“e”键后的GRUB屏幕。通过箭头键下移到kernel行，并按“e”键，</h4><h4 style=\"text-align: start;\">3、在尾行光标处添加single，按回车键返回前一个屏幕，按“b”键进行引导，则系统自动进入单用户模式，如果要改变root密码，则执行命令：sh-3.1# passwd root</h4><p style=\"text-align: start;\">更改成功后，执行命令exit退出重启即可。</p><p style=\"text-align: start;\">大家可以在单用户模式中去纠正阻止系统正常启动的很多问题，比如：</p><h4 style=\"text-align: start;\">1、 禁用可能中止系统运行的服务如禁用Samba服务，则执行：</h4><p style=\"text-align: start;\">sh-3.1# chkconfig smb off下次系统引导就不会启动Samba服务了。</p><h4 style=\"text-align: start;\">2、 更改系统缺省运行级如果X Window无法启动或者出现故障，可以编辑/etc/inittab文件，采用文本方式登录，更改initdefault引导级别为3：id：3：initdefault：</h4><h2 style=\"text-align: start;\">案例二：硬盘扇区错乱</h2><p style=\"text-align: start;\">在启动过程中最容易遇到的问题就是硬盘可能有坏道或扇区错乱(数据损坏)的情况，这种情况多由于异常断电、不正常关机导致。此种问题发生，在系统启动的时候，屏幕会显示：Press root password or ctrl+D：此时输入root密码系统自动进入单用户模式，输入“fsck -y /dev/hda6”(fsck为文件系统检测修复命令，“-y”设定检测到错误自动修复，/dev/hda6为发生错误的硬盘分区，请依据具体情况更改此参数)，系统修复完成后，用命令“reboot”重新启动即可。</p><h2 style=\"text-align: start;\">案例三、GRUB选项设置错误</h2><p style=\"text-align: start;\">“Error 15”显示系统无法找到grub.conf中指定的内核。 GRUB引导错误信息，我们观察发现因为打字错误，内核文件的“vmlinuz”打成了“vmlinux”，所以系统无法找到内核的可执行文件。我们可以按任意键回到GRUB编辑界面，修改此错误，回车保存后按“b”键即可正常引导，当然不要忘记进入系统后修改grub.conf文件中此处错误。这是很多初学Linux的用户在修改GRUB设置时很容易犯的错误，出现此黑屏提示时注意观察报错信息，即可针对性修复。</p><h1 style=\"text-align: start;\">（二）GRUB引导故障排除</h1><p style=\"text-align: start;\">我发现有时Linux启动后会直接进入GRUB命令行界面(只有“grub&gt;”提示符)，此时很多用户就选择了重新安装GRUB甚至重新安装系统。其实一般而言此故障的原因最常见的有两个：一是GRUB配置文件中选项设置错误;二是GRUB配置文件丢失(还有少数原因，如内核文件或镜像文件损坏、丢失，/boot目录误删除等)，如果是第一种情况，可以首先通过GRUB命令引导系统后修复;若是第二种情况，则要使用Linux救援模式修复了(本文后续有描述)。</p><p style=\"text-align: start;\">首先，我们需要了解GRUB启动系统的引导过程，grub.conf文件中主要的配置选项如下(注意，GRUB配置文件为/boot/grub/grub.conf， /etc/grub.conf只是此文件的软链接)：</p><p style=\"text-align: start;\">title Fedora Core (2.6.18-1.2798.fc6)</p><p style=\"text-align: start;\">root (hd0，0)</p><p style=\"text-align: start;\">kernel /boot/vmlinuz-2.6.18-1.2798.fc6 ro root=LABEL=/ rhgb quiet initrd /boot/initrd-2.6.18-1.2798.fc6.img</p><p style=\"text-align: start;\">其中“title”段指定了GRUB引导的系统：“root”段指定了/boot分区所在的位置：“kernel”段指定了内核文件所在位置，内核加载时权限属性为只读(“ro”)以及指定根分区所在位置(root=LABEL=/);initrd指定了镜像文件所在位置。所以GRUB在引导时顺序为首先加载/boot分区，然后依次载入内核与镜像文件。</p><h2 style=\"text-align: start;\">案例：“title Fedora Core (2.6.18-1.2798.fc6)”段被误删除</h2><p style=\"text-align: start;\">此时，系统启动后会自动进入“GRUB&gt;”命令行，为排除故障我们可以依次做如下操作：</p><h4 style=\"text-align: start;\">1、查找/boot/grub/grub.conf文件所在分区GRUB&gt; find /boot/grub/grub.conf(hd0，0)</h4><h4 style=\"text-align: start;\">2、查看grub.conf文件错误GRUB&gt;cat (hd0，0)/boot/grub/grub.conf建议系统安装设置好后，要将grub.conf文件备份，如果有备份文件如grub.conf.bak，则此时可以查看备份文件，与当前文件比较，发现错误：GRUB&gt;cat (hd0，0)/boot/grub/grub.conf.bak</h4><h4 style=\"text-align: start;\">3、确认错误后，先通过命令行方式完成GRUB引导，进入系统后再行修复grub.conf文件错误：</h4><h5 style=\"text-align: start;\">（1)指定/boot分区root (hd0，0)</h5><h5 style=\"text-align: start;\">（2)指定内核加载kernel</h5><h5 style=\"text-align: start;\">/boot/vmlinuz-2.6.18-1.2798.fc6 ro root=LABEL=/ rhgb quiet 3)指定镜像文件所在位置initrd /boot/initrd-2.6.18-1.2798.fc6.img</h5><h5 style=\"text-align: start;\">提示：GRUB支持tab键命令补全功能</h5><h4 style=\"text-align: start;\">4、从/boot分区启动boot (hd0，0)</h4><p style=\"text-align: start;\">命令行模式可以在GRUB菜单模式中通过按“c”键调用，也可以用于测试新编译的内核(设置kernel、initrd引导新内核及镜像文件)。增加对GRUB引导以及Linux系统引导知识的了解将对此类故障排除大有帮助。</p><h1 style=\"text-align: start;\">（三）Linux救援模式应用</h1><h3 style=\"text-align: start;\">当系统连单用户模式都无法进入时或出现GRUB命令行也不能解决的引导问题，我们就需要使用Linux救援模式来进行故障排除了。步骤如下：</h3><h4 style=\"text-align: start;\">1、将Linux安装光盘(如果使用CD光盘，则放入第一张引导光盘)放入光驱，设置固件CMOS/BIOS为光盘引导，当Linux安装画面出现后，在“boot：”提示符后输入“linux rescue”回车进入救援模式。(想了解救援模式详细信息，还可以按F5键查看)</h4><h4 style=\"text-align: start;\">2、系统会检测硬件，引导光盘上的Linux环境，依次提示你选择救援模式下使用的语言(建议选择默认的英文即可，根据笔者测试，部分Linux系统选择中文会出现乱码);键盘设置用默认的“us”就好;网络设置可以根据需要，大部分故障修复不需要网络连接，可不进行此项设置，选择“No”。</h4><h4 style=\"text-align: start;\">3、接下来系统将试图查找根分区，出现挂载提示，设置默认在救援模式，硬盘的根分区将挂载到光盘Linux环境的/mnt/sysimage目录下，默认选项“continue”表示挂载权限为读写：“Read-only”为只读，如果出现检测失败可以选择“skip”跳过。此处，因为要对系统进行修复，所以需要有读写权限，一般选择默认选项“continue”。</h4><p style=\"text-align: start;\">进入下一步后，系统提示执行“chroot /mnt/sysimage”命令，可以将根目录挂载到我们硬盘系统的根目录中去。</p><h2 style=\"text-align: start;\">案例一：双系统启动修复</h2><p style=\"text-align: start;\">当我们安装双系统环境，先安装Linux再安装Windows;或者已经安装好双系统环境的Windows损坏，在重新安装Windows后，保存 GRUB的MBR(Master Boot Record，主引导记录)会被Windows系统的自举程序NTLDR所覆盖，造成Linux系统无法引导。</p><h3 style=\"text-align: start;\">1、如果要恢复双系统引导，首先用上述方法进入救援模式，执行chroot命令如下：sh-3.1# chroot /mnt/sysimage</h3><h3 style=\"text-align: start;\">2、将根目录切换到硬盘系统的根目录中，然后执行grub-install命令重新安装GRUB：sh-3.1# grub-install /dev/hda“/dev/hda”为硬盘名称，如使用SCSI硬盘或Linux安装在第二块IDE硬盘，此项设置要做相应调整。</h3><h3 style=\"text-align: start;\">3、然后依次执行exit命令，退出chroot模式及救援模式(执行两次exit命令)：sh-3.1# exit系统重启后，将恢复GRUB引导的双系统启动。</h3><h2 style=\"text-align: start;\">案例二：系统配置文件丢失修复</h2><p style=\"text-align: start;\">系统在引导期间，很重要的一个过程就是init进程读取其配置文件/etc/inittab，启动系统基本服务程序及默认运行级别的服务程序完成系统引导，如果/etc/inittab误删除或修改错误，Linux将无法正常启动，如图7所示。此时，只有通过救援模式才可以解决此类问题。</p><p style=\"text-align: start;\">/etc/inittab文件丢失引导错误示例</p><h4 style=\"text-align: start;\">1、有备份文件的恢复办法进入救援模式，执行chroot命令后，如果有此文件的备份(强烈建议系统中的重要数据目录，如/etc、/boot等要进行备份)，直接将备份文件拷贝回去，退出重启即可。如果是配置文件修改错误，如比较典型的/boot/grub/grub.conf及/etc/passwd的文件修改错误，也可以直接修正恢复。假设有备份文件/etc/inittab.bak，则在救援模式下执行：sh-3.1# chroot /mnt/sysimage sh-3.1# cp /etc/inittab.bak /etc/inittab</h4><h4 style=\"text-align: start;\">2、没有备份文件的恢复办法如果一些配置文件丢失或软件误删除，且无备份，可以通过重新安装软件包来恢复，首先查找到/etc/inittab属于哪一个RPM包(即便文件丢失，因为存在RPM数据库，一样可以查找到结果)：sh-3.1# chroot /mnt/sysimage sh-3.1# rpm -qf /etc/inittab initscripts-8.45.3-1</h4><p style=\"text-align: start;\">退出chroot模式：sh-3.1# exit</p><p style=\"text-align: start;\">挂载存放RPM包的安装光盘(在救援模式下，光盘通常挂载在/mnt/source目录下)：sh-3.1# mount /dev/hdc /mnt/source</p><p style=\"text-align: start;\">Fedora系统的RPM包存放在光盘Fedora/RPMS目录下，其他Linux存放位置大同小异，我在这里不一一列举;另外，因为要修复的硬盘系统的根目录在/mnt/sysimage下，需要使用——root选项指定其位置。覆盖安装/etc/inittab文件所在的RPM包：sh-3.1# rpm -ivh ——replacepkgs ——root /mnt/sysimage/mnt/source/Fedora/RPMS/ initscripts-8.45.3-1.i386.rpm其中的rpm命令选项“——replacepkgs”表示覆盖安装，执行完成后，即已经恢复了此文件。</p><p style=\"text-align: start;\">如果想只提取RPM包中的/etc/inittab文件进行恢复，可以在进入救援模式后，执行命令：sh-3.1# rpm2cpio /mnt/source/Fedora/RPMS/initscripts-8.45.3-1.i386.rpm | cpio -idv ./etc/inittab sh-3.1# cp etc/inittab /mnt/sysimage/etc</p><p style=\"text-align: start;\">注意此命令执行时不能将文件直接恢复至/etc目录，只能提取到当前目录下，且恢复的文件名称所在路径要写完整的绝对路径。提取文件成功后，将其复制到根分区所在的/mnt/sysimage目录下相应位置即可。</p><p style=\"text-align: start;\">救援模式是维护Linux的有力武器，本文以上述两个例子讲解了它的应用方法，希望能够给读者一点启示。解决Linux系统启动的故障，必须充分理解Linux的引导过程，才能够对故障进行有效的判断和处理。</p>', '我发现Linux系统在启动过程中会出现一些故障，导致系统无法正常启动，我在这里写了几个应用单用户模式、GRUB命令操作、Linux救援模式的故障修复案例帮助大家了解此类问题的解决。', '/uploads/2026/03/1774445242660-l5hyf7vkuoo.png', 'published', 1, 0, '2026-03-25 14:36:48', '2026-03-25 14:46:50', 4, 1, '2025-08-05 14:36:00');
INSERT INTO `articles` VALUES (5, 'iptables 实战指南：从原理到生产环境防火墙配置', 'iptables', '<h2 style=\"text-align: start;\">前言</h2><p style=\"text-align: start;\">iptables 是 Linux 系统中最经典的防火墙工具，虽然近年来 nftables 逐渐成为主流，但仍有大量生产环境在使用 iptables。本文将从原理到实战，带你全面掌握 iptables 的配置技巧。</p><h2 style=\"text-align: start;\">一、iptables 核心概念</h2><h3 style=\"text-align: start;\">1.1 四表五链</h3><p style=\"text-align: start;\">iptables 的核心架构由\"四表五链\"组成：</p><p style=\"text-align: start;\"><strong>四表：</strong></p><ul><li style=\"text-align: start;\"><strong>filter 表</strong>：默认表，用于数据包过滤</li><li style=\"text-align: start;\"><strong>nat 表</strong>：网络地址转换</li><li style=\"text-align: start;\"><strong>mangle 表</strong>：修改数据包内容</li><li style=\"text-align: start;\"><strong>raw 表</strong>：连接跟踪处理</li></ul><p style=\"text-align: start;\"><strong>五链：</strong></p><ul><li style=\"text-align: start;\"><strong>INPUT</strong>：处理入站数据包</li><li style=\"text-align: start;\"><strong>OUTPUT</strong>：处理出站数据包</li><li style=\"text-align: start;\"><strong>FORWARD</strong>：处理转发数据包</li><li style=\"text-align: start;\"><strong>PREROUTING</strong>：路由前处理</li><li style=\"text-align: start;\"><strong>POSTROUTING</strong>：路由后处理</li></ul><h3 style=\"text-align: start;\">1.2 数据包流向</h3><p>复制代码</p><pre><code >入站数据包 → PREROUTING → INPUT → 本地进程\r\n                              ↓\r\n转发数据包 → PREROUTING → FORWARD → POSTROUTING\r\n                              ↓\r\n出站数据包 → OUTPUT → POSTROUTING → 网络</code></pre><h2 style=\"text-align: start;\">二、常用命令速查</h2><h3 style=\"text-align: start;\">2.1 查看规则</h3><p>bash复制代码</p><pre><code class=\"language-bash\"># 查看所有表的规则\r\niptables -L -n -v\r\n\r\n# 查看指定表\r\niptables -t nat -L -n -v\r\n\r\n# 查看规则带行号\r\niptables -L -n --line-numbers</code></pre><h3 style=\"text-align: start;\">2.2 添加规则</h3><p>bash复制代码</p><pre><code class=\"language-bash\"># 添加规则到链末尾\r\niptables -A INPUT -p tcp --dport 22 -j ACCEPT\r\n\r\n# 插入规则到指定位置\r\niptables -I INPUT 1 -p tcp --dport 80 -j ACCEPT\r\n\r\n# 追加到指定链\r\niptables -A OUTPUT -p tcp --dport 443 -j ACCEPT</code></pre><h3 style=\"text-align: start;\">2.3 删除规则</h3><p>bash复制代码</p><pre><code class=\"language-bash\"># 按行号删除\r\niptables -D INPUT 1\r\n\r\n# 按规则删除\r\niptables -D INPUT -p tcp --dport 22 -j ACCEPT\r\n\r\n# 清空链所有规则\r\niptables -F INPUT\r\n\r\n# 清空所有表\r\niptables -F && iptables -t nat -F && iptables -t mangle -F</code></pre><h3 style=\"text-align: start;\">2.4 设置默认策略</h3><p>bash复制代码</p><pre><code class=\"language-bash\"># 设置默认 DROP（谨慎操作！）\r\niptables -P INPUT DROP\r\niptables -P FORWARD DROP\r\niptables -P OUTPUT ACCEPT</code></pre><h2 style=\"text-align: start;\">三、生产环境配置实例</h2><h3 style=\"text-align: start;\">3.1 基础安全配置</h3><p>bash复制代码</p><pre><code class=\"language-bash\">#!/bin/bash\r\n# 清空现有规则\r\niptables -F\r\niptables -X\r\niptables -t nat -F\r\niptables -t mangle -F\r\n\r\n# 设置默认策略\r\niptables -P INPUT DROP\r\niptables -P FORWARD DROP\r\niptables -P OUTPUT ACCEPT\r\n\r\n# 允许回环接口\r\niptables -A INPUT -i lo -j ACCEPT\r\niptables -A OUTPUT -o lo -j ACCEPT\r\n\r\n# 允许已建立的连接\r\niptables -A INPUT -m state --state ESTABLISHED,RELATED -j ACCEPT\r\n\r\n# 允许 SSH (22 端口)\r\niptables -A INPUT -p tcp --dport 22 -j ACCEPT\r\n\r\n# 允许 HTTP/HTTPS\r\niptables -A INPUT -p tcp --dport 80 -j ACCEPT\r\niptables -A INPUT -p tcp --dport 443 -j ACCEPT\r\n\r\n# 允许 ICMP (ping)\r\niptables -A INPUT -p icmp --icmp-type echo-request -j ACCEPT\r\n\r\n# 防止 SYN 洪水攻击\r\niptables -A INPUT -p tcp --syn -m limit --limit 1/s --limit-burst 3 -j ACCEPT\r\n\r\n# 保存规则 (CentOS/RHEL)\r\nservice iptables save\r\n\r\n# 保存规则 (Ubuntu/Debian)\r\niptables-save &gt; /etc/iptables/rules.v4</code></pre><h3 style=\"text-align: start;\">3.2 Docker 环境配置</h3><p style=\"text-align: start;\">Docker 会修改 iptables 规则，需要注意：</p><p style=\"text-align: start;\">bash复制代码</p><pre><code class=\"language-bash\"># 允许 Docker 网桥\r\niptables -A FORWARD -i docker0 -j ACCEPT\r\niptables -A FORWARD -o docker0 -j ACCEPT\r\n\r\n# 或者禁用 Docker 自动修改 iptables\r\n# 在 /etc/docker/daemon.json 中添加:\r\n# {\"iptables\": false}</code></pre><h3 style=\"text-align: start;\">3.3 端口转发配置</h3><p>bash复制代码</p><pre><code class=\"language-bash\"># 开启 IP 转发\r\necho 1 &gt; /proc/sys/net/ipv4/ip_forward\r\n\r\n# 将 8080 端口转发到 80\r\niptables -t nat -A PREROUTING -p tcp --dport 8080 -j REDIRECT --to-port 80\r\n\r\n# 转发到其他服务器\r\niptables -t nat -A PREROUTING -p tcp --dport 8080 -j DNAT --to-destination 192.168.1.100:80\r\niptables -t nat -A POSTROUTING -j MASQUERADE</code></pre><h3 style=\"text-align: start;\">3.4 限制 IP 访问</h3><p>bash复制代码</p><pre><code class=\"language-bash\"># 封禁单个 IP\r\niptables -A INPUT -s 192.168.1.100 -j DROP\r\n\r\n# 封禁网段\r\niptables -A INPUT -s 192.168.1.0/24 -j DROP\r\n\r\n# 只允许特定 IP 访问 SSH\r\niptables -A INPUT -p tcp -s 10.0.0.0/24 --dport 22 -j ACCEPT\r\niptables -A INPUT -p tcp --dport 22 -j DROP</code></pre><h2 style=\"text-align: start;\">四、故障排查技巧</h2><h3 style=\"text-align: start;\">4.1 查看连接状态</h3><p>bash复制代码</p><pre><code class=\"language-bash\"># 查看连接跟踪\r\nconntrack -L\r\n\r\n# 查看 NAT 表\r\niptables -t nat -L -n -v\r\n\r\n# 实时查看匹配的数据包\r\nwatch -n 1 \'iptables -L -n -v | grep -E \"^Chain|pkts\"\'</code></pre><h3 style=\"text-align: start;\">4.2 日志记录</h3><p>bash复制代码</p><pre><code class=\"language-bash\"># 添加日志记录\r\niptables -A INPUT -j LOG --log-prefix \"IPT_INPUT_DROP: \" --log-level 4\r\n\r\n# 查看日志\r\ntail -f /var/log/messages | grep IPT\r\n# 或\r\ntail -f /var/log/syslog | grep IPT</code></pre><h3 style=\"text-align: start;\">4.3 常见问题</h3><p style=\"text-align: start;\"><strong>问题 1：规则不生效</strong></p><ul><li style=\"text-align: start;\">检查规则顺序（iptables 从上到下匹配）</li><li style=\"text-align: start;\">确认默认策略</li><li style=\"text-align: start;\">检查是否有其他防火墙（firewalld、ufw）冲突</li></ul><p style=\"text-align: start;\"><strong>问题 2：重启后规则丢失</strong></p><ul><li style=\"text-align: start;\">确保执行了保存操作</li><li style=\"text-align: start;\">检查 iptables 服务是否开机自启</li></ul><p style=\"text-align: start;\"><strong>问题 3：影响 Docker 容器网络</strong></p><ul><li style=\"text-align: start;\">Docker 依赖 iptables 进行 NAT</li><li style=\"text-align: start;\">修改前备份规则，或在 Docker 配置中禁用 iptables 管理</li></ul><h2 style=\"text-align: start;\">五、最佳实践建议</h2><ol><li style=\"text-align: start;\"><strong>先放行后限制</strong>：先配置允许的规则，最后设置默认 DROP</li><li style=\"text-align: start;\"><strong>保留 SSH 会话</strong>：修改防火墙时保持 SSH 连接，避免被锁在外面</li><li style=\"text-align: start;\"><strong>定期审计规则</strong>：使用 <span style=\"color: rgb(53, 148, 247); background-color: rgba(59, 170, 250, 0.1);\"><code>iptables -L -n --line-numbers</code></span> 定期检查</li><li style=\"text-align: start;\"><strong>版本控制</strong>：将规则保存到文件中，纳入版本管理</li><li style=\"text-align: start;\"><strong>测试环境验证</strong>：生产环境变更前先在测试环境验证</li><li style=\"text-align: start;\"><strong>备份恢复方案</strong>：</li></ol><h2 style=\"text-align: start;\">六、从 iptables 迁移到 nftables</h2><p style=\"text-align: start;\">如果你考虑升级到 nftables：</p><p style=\"text-align: start;\">bash复制代码</p><pre><code class=\"language-bash\"># 查看是否支持 nftables\r\nnft --version\r\n\r\n# 使用 nftables 语法实现相同功能\r\nnft add table inet filter\r\nnft add chain inet filter input { type filter hook input priority 0 \\; policy drop \\; }\r\nnft add rule inet filter input tcp dport 22 accept</code></pre><h2 style=\"text-align: start;\">总结</h2><p style=\"text-align: start;\">iptables 作为成熟的防火墙解决方案，在生产环境中依然有重要价值。掌握其核心原理和配置技巧，能够帮助你构建安全的网络环境。</p><p style=\"text-align: start;\">关键要点：</p><ul><li style=\"text-align: start;\">理解四表五链和数据包流向</li><li style=\"text-align: start;\">遵循\"最小权限原则\"配置规则</li><li style=\"text-align: start;\">做好规则备份和恢复预案</li><li style=\"text-align: start;\">定期审计和优化规则集</li></ul><hr/><p><br></p><p style=\"text-align: start;\"><strong>参考资料：</strong></p><ul><li style=\"text-align: start;\"><a href=\"https://www.netfilter.org/documentation/\" target=\"\" style=\"line-height: 1;\">iptables 官方文档</a></li><li style=\"text-align: start;\"><a href=\"https://example.com/\" target=\"\" style=\"line-height: 1;\">Linux 防火墙深度解析</a></li></ul><p style=\"text-align: start;\"><em>本文首发于漫辰夕 BLOG，转载请注明出处。</em></p><ul><li style=\"text-align: start;\"></li><li style=\"text-align: start;\"></li></ul>', 'iptables 是 Linux 系统中最经典的防火墙工具，虽然近年来 nftables 逐渐成为主流，但仍有大量生产环境在使用 iptables。本文将从原理到实战，带你全面掌握 iptables 的配置技巧。', '/uploads/2026/03/1774448986332-gq6usyjo5e.png', 'published', 5, 0, '2026-03-25 14:39:35', '2026-03-25 17:21:48', 4, 1, '2025-11-10 14:38:00');
INSERT INTO `articles` VALUES (6, 'GPU 压测神器 fieldiag 全解析——从显存到温度，15 分钟入门', 'gpu-fieldiag-15', '<p style=\"text-align: start;\">如果你手里有一张 A100/H100，或者即将接手一台 8-GPU 的 HGX 模组，<strong>“跑个 fieldiag 先”</strong> 一定是工程师挂在嘴边的一句话。它就像体检表：血压、心电图、B 超一次做完，GPU 能不能扛住 7×24 的 AI 训练，全看这张“成绩单”。</p><p style=\"text-align: start;\">今天这篇，把 fieldiag 到底在跑什么、怎么看报告、以及常见翻车点，一次性讲清。看完你能：</p><ul><li style=\"text-align: start;\">5 分钟给同事讲明白 fieldiag 是干啥的</li><li style=\"text-align: start;\">30 秒定位“哪颗 GPU 挂了”</li><li style=\"text-align: start;\">避免“测完温度才发现电源线松了”的尴尬</li></ul><hr/><p><br></p><h2 style=\"text-align: start;\">1. fieldiag 是什么？</h2><p style=\"text-align: start;\">一句话：<strong>NV 官方 RMA 的“体检表”</strong>。</p><ul><li style=\"text-align: start;\">支持全系列 GPU：从 PCIe 单卡到 8-GPU HGX 模组</li><li style=\"text-align: start;\">输出三种结果：PASS / FAIL / RETEST</li><li style=\"text-align: start;\">生成日志：<span style=\"color: rgb(53, 148, 247); background-color: rgba(59, 170, 250, 0.1);\"><code>logs-yyyymmdd-hhnnss.tgz</code></span>，售后工程师第一眼就看它</li></ul><hr/><p><br></p><h2 style=\"text-align: start;\">2. 三步起跑——先把环境搭好</h2><ol><li style=\"text-align: start;\">做个启动 U 盘（Ubuntu 20.04 + 官方 fieldiag 包）</li><li style=\"text-align: start;\">插到目标机器，U 盘启动</li><li style=\"text-align: start;\">一行命令开跑：</li></ol><p style=\"text-align: start;\">bash<br>./fieldiag.sh --level2 # 最常用，2 小时完事</p><blockquote style=\"text-align: start;\">小贴士：远程客户现场，让值班小哥拍个屏幕照片就行，日志回头再收。</blockquote><hr/><p><br></p><h2 style=\"text-align: start;\">3. 测试项目全景图</h2><table style=\"width: auto; text-align: start;\"><tbody><tr><th colspan=\"1\" rowspan=\"1\" width=\"auto\">模块</th><th colspan=\"1\" rowspan=\"1\" width=\"auto\">耗时</th><th colspan=\"1\" rowspan=\"1\" width=\"auto\">测什么</th><th colspan=\"1\" rowspan=\"1\" width=\"auto\">翻车现场</th></tr><tr><td colspan=\"1\" rowspan=\"1\" width=\"auto\">skucheck</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">15 min</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">GPU 基本配置、电源、PCIe 速率</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">电源线少插一根，直接 FAIL</td></tr><tr><td colspan=\"1\" rowspan=\"1\" width=\"auto\">connectivity</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">16 min</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">NVLink 物理链路、PCIe 速率/宽度</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">某槽位只跑 ×8，原来是转接卡坏了</td></tr><tr><td colspan=\"1\" rowspan=\"1\" width=\"auto\">gpumem</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">5 min</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">显存颗粒 + FBIO 接口</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">显存坏块，训练到 3% 直接崩</td></tr><tr><td colspan=\"1\" rowspan=\"1\" width=\"auto\">cudacores</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">9 min</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">CUDA Core 指令正确性</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">核心掩码错误，算子跑不出结果</td></tr><tr><td colspan=\"1\" rowspan=\"1\" width=\"auto\">pcie</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">13 min</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">眼图、速率切换</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">信号完整性差，降到 ×8 才能稳</td></tr><tr><td colspan=\"1\" rowspan=\"1\" width=\"auto\">nvlink</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">24 min</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">NVLink 带宽 + 眼图</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">链路重传率 &gt;1%，多卡训练掉速</td></tr><tr><td colspan=\"1\" rowspan=\"1\" width=\"auto\">nvswitch</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">13 min</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">Switch 芯片眼图</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">8-GPU 拓扑里 Switch 挂了，全网瘫痪</td></tr><tr><td colspan=\"1\" rowspan=\"1\" width=\"auto\">gpustress</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">7 min</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">满载 GPU 核心</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">频率飙到 97℃ 降频，风扇曲线没调好</td></tr><tr><td colspan=\"1\" rowspan=\"1\" width=\"auto\">power</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">24 min</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">GPU + NVSwitch 供电压力</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">电源瞬载跌落，触发 PSU OCP</td></tr><tr><td colspan=\"1\" rowspan=\"1\" width=\"auto\">thermal</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">2 h 16 min</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">持续高温 85℃+</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">风道被网线挡住，热点死机</td></tr></tbody></table><hr/><p><br></p><h2 style=\"text-align: start;\">4. 报告长啥样？</h2><p style=\"text-align: start;\">测完会蹦出三选一的“表情包”：</p><ul><li style=\"text-align: start;\">✅ <strong>PASS</strong>：放心上线，该吃吃该睡睡</li><li style=\"text-align: start;\">❌ <strong>FAIL</strong>：日志里会精确到“GPU-2 nvlink 眼图失败”，按图索骥换卡</li><li style=\"text-align: start;\">🔄 <strong>RETEST</strong>：环境异常（U 盘掉了、PCIe 降速了），擦干净重来<br>日志包解压后重点关注：</li></ul><p style=\"text-align: start;\">result.xml # 一眼看结果<br>nvlink-eye/*.png # 眼图照片，波浪线越干净越好<br>gpumem.log # 显存错误比特数 &gt;0 就完蛋</p><hr/><p><br></p><h2 style=\"text-align: start;\">5. 个人踩坑 Top 3</h2><ol><li style=\"text-align: start;\"><strong>“测完 thermal 才想起风扇没插”</strong><br>现场吵得要死，一看转速 0，当场社死。</li><li style=\"text-align: start;\"><strong>“电源线看似插紧，其实卡扣没合”</strong><br>power 测试随机 FAIL，轻轻一推就好了，客户看你眼神都变了。</li><li style=\"text-align: start;\"><strong>“日志太大，U 盘满了”</strong><br>建议 16G 起步，测完即刻把日志拷走，别等第二天现场小哥把 U 盘弄丢。</li></ol><hr/><p><br></p><h2 style=\"text-align: start;\">6. 一句话速记版</h2><h2 style=\"text-align: start;\">skucheck 看“有没有”，connectivity 看“通不通”，gpumem 看“错没错”，thermal 看“热不热”；四关全绿，GPU 才能“毕业”。</h2>', '如果你手里有一张 A100/H100，或者即将接手一台 8-GPU 的 HGX 模组，“跑个 fieldiag 先” 一定是工程师挂在嘴边的一句话。它就像体检表：血压、心电图、B 超一次做完，GPU 能不能扛住 7×24 的 AI 训练，全看这张“成绩单”。', '/uploads/2026/03/1774450091052-5q4m91lj1dq.png', 'published', 5, 0, '2026-03-25 14:48:45', '2026-03-25 17:21:48', 4, 1, '2025-10-01 10:46:00');

-- ----------------------------
-- Table structure for articletags
-- ----------------------------
DROP TABLE IF EXISTS `articletags`;
CREATE TABLE `articletags`  (
  `createdAt` datetime NOT NULL,
  `updatedAt` datetime NOT NULL,
  `ArticleId` int NOT NULL,
  `TagId` int NOT NULL,
  PRIMARY KEY (`ArticleId`, `TagId`) USING BTREE,
  INDEX `TagId`(`TagId` ASC) USING BTREE,
  CONSTRAINT `articletags_ibfk_1` FOREIGN KEY (`ArticleId`) REFERENCES `articles` (`id`) ON DELETE CASCADE ON UPDATE CASCADE,
  CONSTRAINT `articletags_ibfk_2` FOREIGN KEY (`TagId`) REFERENCES `tags` (`id`) ON DELETE CASCADE ON UPDATE CASCADE
) ENGINE = InnoDB CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci ROW_FORMAT = Dynamic;

