-- ----------------------------
-- Table structure for pages
-- ----------------------------
DROP TABLE IF EXISTS `pages`;
CREATE TABLE `pages`  (
  `id` int NOT NULL AUTO_INCREMENT,
  `title` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL,
  `slug` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL,
  `content` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL,
  `status` enum('published','hidden') CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT 'published',
  `views` int NULL DEFAULT 0,
  `createdAt` datetime NOT NULL,
  `updatedAt` datetime NOT NULL,
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `unique_page_slug`(`slug` ASC) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 2 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci ROW_FORMAT = Dynamic;

-- ----------------------------
-- Records of pages
-- ----------------------------
INSERT INTO `pages` VALUES (1, 'Memo - 博客系统', 'memo', '<p style=\"text-align: start;\"><br></p><p style=\"text-align: start;\">一个基于 <code>Node.js + Express + EJS + Sequelize + Redis</code> 的博客系统，包含前台博客展示与后台管理，支持文章管理、页面管理、附件库、友情链接、轮播图、导航配置、RSS、站点地图等功能。</p><h2 style=\"text-align: start;\">功能特性</h2><ul><li style=\"text-align: start;\">前后台一体化：前台博客展示，后台内容管理</li><li style=\"text-align: start;\">多数据库支持：SQLite / MySQL / PostgreSQL</li><li style=\"text-align: start;\">Redis 可选：支持 Session 存储、缓存、阅读量增量同步</li><li style=\"text-align: start;\">文章管理：草稿、发布、置顶、分类、标签、封面、预览</li><li style=\"text-align: start;\">独立页面管理</li><li style=\"text-align: start;\">附件库与本地上传目录同步</li><li style=\"text-align: start;\">站点设置：站点信息、导航菜单、轮播图、友情链接</li><li style=\"text-align: start;\">前台能力：归档、搜索、分类页、标签页、友情链接页</li><li style=\"text-align: start;\">Feed 能力：/rss.xml、/sitemap.xml</li><li style=\"text-align: start;\">内容展示增强：代码高亮KaTeX 数学公式Mermaid 图表DOMPurify 内容净化</li><li style=\"text-align: start;\">深浅色主题切换</li></ul><h2 style=\"text-align: start;\">技术栈</h2><ul><li style=\"text-align: start;\">服务端：Node.js、Express</li><li style=\"text-align: start;\">模板引擎：EJS</li><li style=\"text-align: start;\">ORM：Sequelize</li><li style=\"text-align: start;\">数据库驱动：sqlite3、mysql2、pg</li><li style=\"text-align: start;\">会话：express-session、connect-redis</li><li style=\"text-align: start;\">Redis 客户端：ioredis</li><li style=\"text-align: start;\">上传：multer</li><li style=\"text-align: start;\">日志：morgan</li><li style=\"text-align: start;\">方法覆写：method-override</li></ul><h2 style=\"text-align: start;\">快速开始</h2><h3 style=\"text-align: start;\">1. 安装依赖</h3><pre style=\"text-align: left;\"><code>npm install</code></pre><h3 style=\"text-align: start;\">2. 配置环境变量</h3><p style=\"text-align: start;\">复制 <code>.env.example</code> 为 <code>.env</code>，按需修改。</p><p style=\"text-align: start;\">示例：</p><pre style=\"text-align: left;\"><code>PORT=3000\r\nSESSION_SECRET=your-secret-key-change-this\r\n​DB_DIALECT=sqlite\r\nDB_STORAGE=./database.sqlite​\r\nREDIS_ENABLED=true\r\nREDIS_HOST=localhost\r\nREDIS_PORT=6379\r\nREDIS_PASSWORD=​\r\nSITE_TITLE=\r\nMemoSITE_DESCRIPTION=分享技术与生活\r\nSITE_KEYWORDS=博客,技术,生活</code></pre><h3 style=\"text-align: start;\">3. 初始化项目</h3><pre style=\"text-align: left;\"><code>npm run init</code></pre><p style=\"text-align: start;\">初始化脚本会：</p><ul><li style=\"text-align: start;\">创建数据库表</li><li style=\"text-align: start;\">创建默认管理员账号</li><li style=\"text-align: start;\">初始化站点设置</li><li style=\"text-align: start;\">初始化示例分类、标签、文章</li><li style=\"text-align: start;\">自动补充默认轮播图数据</li></ul><p style=\"text-align: start;\">默认管理员账号：</p><ul><li style=\"text-align: start;\">用户名：admin</li><li style=\"text-align: start;\">密码：admin123456</li></ul><p style=\"text-align: start;\">首次登录后请立即修改密码。</p><h3 style=\"text-align: start;\">4. 启动项目</h3><p style=\"text-align: start;\">开发模式：</p><pre style=\"text-align: left;\"><code>npm run dev</code></pre><p style=\"text-align: start;\">生产模式：</p><pre style=\"text-align: left;\"><code>npm start</code></pre><p style=\"text-align: start;\">启动后访问：</p><ul><li style=\"text-align: start;\">前台：http://localhost:3000</li><li style=\"text-align: start;\">后台：http://localhost:3000/admin</li></ul><h2 style=\"text-align: start;\">环境变量说明</h2><h3 style=\"text-align: start;\">应用</h3><ul><li style=\"text-align: start;\">PORT：服务端口</li><li style=\"text-align: start;\">SESSION_SECRET：Session 密钥</li></ul><h3 style=\"text-align: start;\">数据库</h3><ul><li style=\"text-align: start;\">DB_DIALECT：sqlite / mysql / postgres</li><li style=\"text-align: start;\">DB_STORAGE：SQLite 文件路径</li><li style=\"text-align: start;\">DB_HOST</li><li style=\"text-align: start;\">DB_PORT</li><li style=\"text-align: start;\">DB_NAME</li><li style=\"text-align: start;\">DB_USER</li><li style=\"text-align: start;\">DB_PASSWORD</li></ul><h3 style=\"text-align: start;\">Redis</h3><ul><li style=\"text-align: start;\">REDIS_ENABLED：设为 false 时禁用 Redis</li><li style=\"text-align: start;\">REDIS_HOST</li><li style=\"text-align: start;\">REDIS_PORT</li><li style=\"text-align: start;\">REDIS_PASSWORD</li></ul><h3 style=\"text-align: start;\">默认站点信息</h3><ul><li style=\"text-align: start;\">SITE_TITLE</li><li style=\"text-align: start;\">SITE_DESCRIPTION</li><li style=\"text-align: start;\">SITE_KEYWORDS</li></ul><h2 style=\"text-align: start;\">数据库说明</h2><p style=\"text-align: start;\">项目通过 Sequelize 统一适配数据库。</p><h3 style=\"text-align: start;\">SQLite</h3><p style=\"text-align: start;\">适合本地开发、单机部署、快速试用：</p><pre style=\"text-align: left;\"><code>DB_DIALECT=sqlite\r\nDB_STORAGE=./database.sqlite</code></pre><h3 style=\"text-align: start;\">MySQL</h3><p style=\"text-align: start;\">适合常规生产环境：</p><pre style=\"text-align: left;\"><code>DB_DIALECT=mysql\r\nDB_HOST=localhost\r\nDB_PORT=3306\r\nDB_NAME=blog\r\nDB_USER=root\r\nDB_PASSWORD=123456</code></pre><h3 style=\"text-align: start;\">PostgreSQL</h3><p style=\"text-align: start;\">同样支持：</p><pre style=\"text-align: left;\"><code>DB_DIALECT=postgres\r\nDB_HOST=localhost\r\nDB_PORT=5432\r\nDB_NAME=blog\r\nDB_USER=postgres\r\nDB_PASSWORD=123456</code></pre><h2 style=\"text-align: start;\">Redis 说明</h2><p style=\"text-align: start;\">Redis 不是强制依赖。</p><p style=\"text-align: start;\">当 <code>REDIS_ENABLED=true</code> 时：</p><ul><li style=\"text-align: start;\">Session 使用 Redis Store</li><li style=\"text-align: start;\">缓存能力开启</li><li style=\"text-align: start;\">阅读量会按间隔同步回数据库</li></ul><p style=\"text-align: start;\">当 <code>REDIS_ENABLED=false</code> 时：</p><ul><li style=\"text-align: start;\">Session 回退到内存存储</li><li style=\"text-align: start;\">缓存逻辑跳过</li><li style=\"text-align: start;\">项目仍可运行</li></ul><p style=\"text-align: start;\">禁用示例：</p><pre style=\"text-align: left;\"><code>REDIS_ENABLED=false</code></pre><h2 style=\"text-align: start;\">主要路由</h2><h3 style=\"text-align: start;\">前台</h3><ul><li style=\"text-align: start;\">/：首页</li><li style=\"text-align: start;\">/archive：归档</li><li style=\"text-align: start;\">/search：搜索</li><li style=\"text-align: start;\">/links：友情链接</li><li style=\"text-align: start;\">/category/:slug：分类页</li><li style=\"text-align: start;\">/tag/:slug：标签页</li><li style=\"text-align: start;\">/article/:slug：文章详情</li><li style=\"text-align: start;\">/p/:slug：独立页面</li><li style=\"text-align: start;\">/article-preview：文章预览页</li><li style=\"text-align: start;\">/rss.xml：RSS</li><li style=\"text-align: start;\">/sitemap.xml：站点地图</li></ul><h3 style=\"text-align: start;\">后台</h3><ul><li style=\"text-align: start;\">/admin：仪表盘</li><li style=\"text-align: start;\">/admin/articles：文章管理</li><li style=\"text-align: start;\">/admin/pages：页面管理</li><li style=\"text-align: start;\">/admin/taxonomy：分类/标签管理</li><li style=\"text-align: start;\">/admin/media：附件库</li><li style=\"text-align: start;\">/admin/settings：站点设置</li><li style=\"text-align: start;\">/admin/profile：个人资料</li></ul><h2 style=\"text-align: start;\">上传与静态文件</h2><ul><li style=\"text-align: start;\">上传目录：uploads/</li><li style=\"text-align: start;\">静态资源目录：public/</li><li style=\"text-align: start;\">上传文件通过 /uploads 暴露</li><li style=\"text-align: start;\">项目启动时会自动确保上传目录存在</li></ul><h2 style=\"text-align: start;\">项目结构</h2><pre style=\"text-align: left;\"><code>.\r\n├─ app.js\r\n├─ init.js\r\n├─ package.json\r\n├─ config/\r\n│  ├─ database.js\r\n│  ├─ redis.js\r\n│  └─ uploadsPath.js\r\n├─ controllers/\r\n├─ middleware/\r\n├─ models/\r\n├─ routes/\r\n├─ utils/\r\n├─ views/\r\n├─ public/\r\n│  ├─ css/\r\n│  ├─ fonts/\r\n│  └─ libs/\r\n└─ uploads/</code></pre><h2 style=\"text-align: start;\">生产运行</h2><p style=\"text-align: start;\">可以使用 <code>pm2</code>：</p><pre style=\"text-align: left;\"><code>pm2 start app.js --name memo-blog</code></pre><h2 style=\"text-align: start;\">默认行为说明</h2><ul><li style=\"text-align: start;\">启动时会执行数据库连接与同步</li><li style=\"text-align: start;\">优先尝试 sequelize.sync({ alter: { drop: false } })</li><li style=\"text-align: start;\">若增量同步失败，会回退为基础同步</li><li style=\"text-align: start;\">开启 Redis 时，阅读量会定时落库</li></ul><h2 style=\"text-align: start;\">适用场景</h2><ul><li style=\"text-align: start;\">个人博客</li><li style=\"text-align: start;\">内网知识库</li><li style=\"text-align: start;\">单机内容管理系统</li><li style=\"text-align: start;\">不希望引入前后端分离复杂度的内容站点</li></ul><h2 style=\"text-align: start;\">License</h2><p style=\"text-align: start;\">本项目采用 知识共享 署名-非商业性使用-相同方式共享 4.0 国际版 (CC BY-NC-SA 4.0) 协议授权。 <br></p><p><br></p>', 'published', 17, '2026-03-25 16:20:04', '2026-03-25 17:26:05');

