INSERT INTO `settings` VALUES (14, 'carousel_items', '[{\"title\":\"Linux LVM逻辑卷管理详解\",\"subtitle\":\"LVM是逻辑盘卷管理（Logical Volume Manager）的简称，它是Linux环境下对磁盘分区进行管理的一种机制，LVM是建立在硬盘和分区之上的一个逻辑层，来提高磁盘分区管理的灵活性。\",\"url\":\"/article/linux-lvm\",\"image\":\"/uploads/2026/03/1774445242660-l5hyf7vkuoo.png\"},{\"title\":\"GPU 压测神器 fieldiag 全解析——从显存到温度，15 分钟入门\",\"subtitle\":\"如果你手里有一张 A100/H100，或者即将接手一台 8-GPU 的 HGX 模组，“跑个 fieldiag 先” 一定是工程师挂在嘴边的一句话。它就像体检表：血压、心电图、B 超一次做完，GPU 能不能扛住 7×24 的 AI 训练，全看这张“成绩单”。\",\"url\":\"/article/gpu-fieldiag-15\",\"image\":\"/uploads/2026/03/1774450091052-5q4m91lj1dq.png\"}]', '2026-03-25 11:06:08', '2026-03-25 15:33:53');
